const input = $input.first().json;
const tool = input.tool || 'query_reviews';
const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const headers = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

if (tool === 'review_summary') {
  // Aggregate stats
  const reviews = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/reviews?select=rating,answered,business_id',
    headers
  });

  if (!reviews || reviews.length === 0) {
    return [{ json: { result: 'Keine Bewertungen in der Datenbank.' } }];
  }

  const total = reviews.length;
  const avgRating = (reviews.reduce((s, r) => s + r.rating, 0) / total).toFixed(1);
  const unanswered = reviews.filter(r => !r.answered).length;
  const byRating = {};
  for (const r of reviews) {
    byRating[r.rating] = (byRating[r.rating] || 0) + 1;
  }

  let result = '📊 BEWERTUNGS-ÜBERSICHT\n';
  result += '  Gesamt: ' + total + ' Bewertungen\n';
  result += '  Durchschnitt: ' + avgRating + ' ⭐\n';
  result += '  Unbeantwortet: ' + unanswered + '\n\n';
  result += '  Verteilung:\n';
  for (let i = 5; i >= 1; i--) {
    const count = byRating[i] || 0;
    const bar = '█'.repeat(Math.round(count / total * 20));
    result += '    ' + i + '⭐ ' + bar + ' ' + count + '\n';
  }

  return [{ json: { result } }];
}

// query_reviews
const businessName = input.business_name || '';
const minRating = input.min_rating || null;
const maxRating = input.max_rating || null;
const sinceDays = input.since_days || 30;

let url = baseUrl + '/rest/v1/reviews?select=*,member_businesses(name,category)&order=fetched_at.desc&limit=20';

if (minRating) url += '&rating=gte.' + minRating;
if (maxRating) url += '&rating=lte.' + maxRating;

const sinceDate = new Date();
sinceDate.setDate(sinceDate.getDate() - sinceDays);
url += '&fetched_at=gte.' + sinceDate.toISOString();

const reviews = await helpers.httpRequest({ method: 'GET', url, headers });

if (!reviews || reviews.length === 0) {
  return [{ json: { result: 'Keine Bewertungen gefunden für die angegebenen Filter.' } }];
}

// Filter by business name if provided
let filtered = reviews;
if (businessName) {
  const search = businessName.toLowerCase();
  filtered = reviews.filter(r =>
    r.member_businesses && r.member_businesses.name &&
    r.member_businesses.name.toLowerCase().includes(search)
  );
}

if (filtered.length === 0) {
  return [{ json: { result: 'Keine Bewertungen für "' + businessName + '" gefunden.' } }];
}

let result = '📝 BEWERTUNGEN (' + filtered.length + ' Ergebnisse)\n\n';
for (const r of filtered) {
  const biz = r.member_businesses ? r.member_businesses.name : 'Unbekannt';
  const stars = '⭐'.repeat(r.rating);
  const date = r.published_at ? new Date(r.published_at).toLocaleDateString('de-DE') : '';
  const status = r.answered ? '✅' : '❌';
  result += biz + ' — ' + stars + ' (' + date + ') ' + status + '\n';
  if (r.author) result += '  Von: ' + r.author + '\n';
  if (r.text) result += '  "' + r.text.substring(0, 200) + (r.text.length > 200 ? '...' : '') + '"\n';
  result += '\n';
}

return [{ json: { result } }];
